<?php
 namespace App\Filters; use CodeIgniter\Filters\FilterInterface; use CodeIgniter\HTTP\RequestInterface; use CodeIgniter\HTTP\ResponseInterface; use Config\Services; use \Firebase\JWT\JWT; use \Firebase\JWT\Key; class AuthFilter implements FilterInterface { public function before(RequestInterface $request, $arguments = null) { if ($request->is('options')) { return; } $header = $request->getServer('HTTP_AUTHORIZATION') ?? $request->getServer('REDIRECT_HTTP_AUTHORIZATION') ?? $request->header('Authorization'); if ($header instanceof \CodeIgniter\HTTP\Header) { $header = $header->getValue(); } if (!$header || empty($header)) { log_message('error', '[AuthFilter] No header found. URI: ' . $request->getUri()->getPath()); return Services::response() ->setJSON(['error' => 'No authorization header provided.', 'debug_uri' => $request->getUri()->getPath()]) ->setStatusCode(ResponseInterface::HTTP_UNAUTHORIZED); } log_message('notice', '[AuthFilter] Header received: ' . substr($header, 0, 15) . '...'); $parts = explode(' ', trim($header)); if (count($parts) < 2) { if (strlen($parts[0]) > 50) { $token = $parts[0]; } else { log_message('error', '[AuthFilter] Malformed header: ' . $header); return Services::response() ->setJSON(['error' => 'Malformed authorization header.']) ->setStatusCode(ResponseInterface::HTTP_UNAUTHORIZED); } } else { $token = $parts[1]; } $key = $_ENV['JWT_SECRET'] ?? getenv('JWT_SECRET') ?? null; if (!$key) { log_message('error', '[AuthFilter] JWT_SECRET missing in environment'); return Services::response()->setJSON(['error' => 'Server configuration error.'])->setStatusCode(ResponseInterface::HTTP_INTERNAL_SERVER_ERROR); } $key = trim($key, '"\' '); try { $decoded = JWT::decode($token, new Key($key, 'HS256')); log_message('notice', '[AuthFilter] Token decoded successfully for UID: ' . $decoded->uid); $uri = $request->getUri()->getPath(); $isAdminRoute = str_starts_with($uri, 'admin/'); $isUploadRoute = str_starts_with($uri, 'upload/'); $isManagementRoute = str_contains($uri, 'admin/course') || str_contains($uri, 'admin/section'); if ($isAdminRoute && !$isManagementRoute && $decoded->role !== 'admin') { return Services::response()->setJSON(['error' => 'Admin role required.']) ->setStatusCode(ResponseInterface::HTTP_FORBIDDEN); } if (($isUploadRoute || $isManagementRoute) && !in_array($decoded->role, ['uploader', 'admin'])) { return Services::response()->setJSON(['error' => 'Contribution privileges required.']) ->setStatusCode(ResponseInterface::HTTP_FORBIDDEN); } } catch (\Exception $e) { return Services::response()->setJSON(['error' => 'Session expired or invalid.', 'details' => $e->getMessage()])->setStatusCode(ResponseInterface::HTTP_UNAUTHORIZED); } } public function after(RequestInterface $request, ResponseInterface $response, $arguments = null) { } }
